class Solution {
    public int findNthDigit(int n) {
        long count = 9;
        int len = 1;
        while (n > len * count) {
            n -= len * count;
            count *= 10;
            len++;
        }
        long num = (long) Math.pow(10, len - 1) + (n - 1) / len;
        return String.valueOf(num).charAt((n - 1) % len) - '0';
    }
}
